import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {
  const navigate = useNavigate();
  const { id } = useParams();

  const isEditMode = Boolean(id);

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    gender: "",
    dob: "",
    maritalStatus: "",
    email: "",
    password: "",
    designation: "",
    department: "",
    salary: "",
    role: "",
    bankName: "",
    accountNumber: "",
    ifsc: "",
    qualification: "",
    university: "",
    passingYear: ""
  });

  // Load employee when editing
  useEffect(() => {
    if (isEditMode) {
      const employees = JSON.parse(localStorage.getItem("employees")) || [];
      const found = employees.find((e) => String(e.id) === String(id));

      if (found) {
        setEmployee({
          ...employee,
          ...found
        });
      }
    }
  }, [id]);

  // Handle input
  const handleChange = (e) => {
    setEmployee({
      ...employee,
      [e.target.name]: e.target.value
    });
  };

  // =========================
  // ⭐ ADD EMPLOYEE
  // =========================
  const handleAdd = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const newEmployee = {
      id: Date.now(),
      name: `${employee.firstName} ${employee.lastName}`.trim(),
      ...employee
    };

    employees.push(newEmployee);
    localStorage.setItem("employees", JSON.stringify(employees));

    alert("Employee Added Successfully!");
    navigate("/dashboard/employee-details");
  };

  // =========================
  // ⭐ UPDATE EMPLOYEE
  // =========================
  const handleUpdate = (e) => {
    e.preventDefault();

    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const updated = employees.map((emp) => {
      if (String(emp.id) === String(id)) {
        return {
          ...emp,

          firstName: employee.firstName,
          lastName: employee.lastName,

          // FULL NAME FIX
          name: `${employee.firstName} ${employee.lastName}`.trim(),

          empId: employee.empId,
          dob: employee.dob,
          gender: employee.gender,
          maritalStatus: employee.maritalStatus,
          email: employee.email,
          password: employee.password,

          designation: employee.designation,
          department: employee.department,
          salary: employee.salary,
          role: employee.role,

          bankName: employee.bankName,
          accountNumber: employee.accountNumber,
          ifsc: employee.ifsc,

          qualification: employee.qualification,
          university: employee.university,
          passingYear: employee.passingYear
        };
      }
      return emp;
    });

    localStorage.setItem("employees", JSON.stringify(updated));

    alert("Employee Updated Successfully!");
    navigate("/dashboard/employee-details");
  };

  return (
    <div className="employee-form-container">
      <h2>{isEditMode ? "Edit Employee" : "Add Employee"}</h2>

      <form className="employee-form" onSubmit={isEditMode ? handleUpdate : handleAdd}>

        {/* PERSONAL */}
        <h4>Personal Details</h4>

        <input
          name="firstName"
          placeholder="First Name"
          value={employee.firstName}
          onChange={handleChange}
        />

        <input
          name="lastName"
          placeholder="Last Name"
          value={employee.lastName}
          onChange={handleChange}
        />

        <input
          name="empId"
          placeholder="Employee ID"
          value={employee.empId}
          onChange={handleChange}
        />

        <select name="gender" value={employee.gender} onChange={handleChange}>
          <option>Gender</option>
          <option>Male</option>
          <option>Female</option>
        </select>

        <input
          type="date"
          name="dob"
          value={employee.dob}
          onChange={handleChange}
        />

        <select
          name="maritalStatus"
          value={employee.maritalStatus}
          onChange={handleChange}
        >
          <option>Marital Status</option>
          <option>Single</option>
          <option>Married</option>
        </select>

        <input
          type="email"
          name="email"
          placeholder="Email"
          value={employee.email}
          onChange={handleChange}
        />

        <input
          type="password"
          name="password"
          placeholder="Password"
          value={employee.password}
          onChange={handleChange}
        />

        {/* JOB */}
        <h4>Job Details</h4>

        <input
          name="designation"
          placeholder="Designation"
          value={employee.designation}
          onChange={handleChange}
        />

        <input
          name="department"
          placeholder="Department"
          value={employee.department}
          onChange={handleChange}
        />

        <input
          name="salary"
          placeholder="Salary"
          value={employee.salary}
          onChange={handleChange}
        />

        <select name="role" value={employee.role} onChange={handleChange}>
          <option>Role</option>
          <option>Employee</option>
          <option>Admin</option>
        </select>

        {/* BANK */}
        <h4>Bank Details</h4>

        <input
          name="bankName"
          placeholder="Bank Name"
          value={employee.bankName}
          onChange={handleChange}
        />

        <input
          name="accountNumber"
          placeholder="Account Number"
          value={employee.accountNumber}
          onChange={handleChange}
        />

        <input
          name="ifsc"
          placeholder="IFSC Code"
          value={employee.ifsc}
          onChange={handleChange}
        />

        {/* EDUCATION */}
        <h4>Educational Details</h4>

        <select
          name="qualification"
          value={employee.qualification}
          onChange={handleChange}
        >
          <option>Highest Qualification</option>
          <option>B.Tech</option>
          <option>M.Tech</option>
          <option>BSc</option>
          <option>MBA</option>
          <option>MCA</option>
          <option>Diploma</option>
        </select>

        <input
          name="university"
          placeholder="University / College"
          value={employee.university}
          onChange={handleChange}
        />

        <input
          name="passingYear"
          placeholder="Year of Passing"
          value={employee.passingYear}
          onChange={handleChange}
        />

        <button type="submit">
          {isEditMode ? "Update Employee" : "Save Employee"}
        </button>
      </form>
    </div>
  );
}

export default AddEmployee;
